package com.example.myapplication;

import android.os.Bundle;
import android.os.CountDownTimer;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.example.myapplication.data.GameResultRepository;
import com.example.myapplication.data.UserRepository;
import com.example.myapplication.model.GameResult;
import com.example.myapplication.model.User;

public class KorakPoKorakActivity extends AppCompatActivity {

    private static final String[] HINTS = {
            "Najteži trag: nije čovek, ali može da se otvara",
            "Drugim tragom postaje jasnije: koristi se za čuvanje stvari",
            "Treći trag: obično ima poklopac i stane na policu",
            "Četvrti trag: u njemu često držimo odelo ili knjige",
            "Peti trag: može biti mali ili veliki, ali služi za stvari kod kuće",
            "Šesti trag: sinonim za ormar",
            "Rešenje je: ormar"
    };

    private TextView timerView;
    private TextView stepNumber;
    private TextView hintText;
    private EditText guessInput;
    private TextView scoreValue;
    private CountDownTimer timer;
    private int stepIndex = 0;
    private int score = 20;
    private final String solution = "ormar";
    private final UserRepository userRepository = new UserRepository(this);
    private final GameResultRepository resultRepository = new GameResultRepository(this);

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_korak_po_korak);

        Button quit = findViewById(R.id.quit_button);
        timerView = findViewById(R.id.timer);
        stepNumber = findViewById(R.id.step_number);
        hintText = findViewById(R.id.hint_text);
        guessInput = findViewById(R.id.guess_input);
        scoreValue = findViewById(R.id.score_value);
        Button submitButton = findViewById(R.id.submit_button);
        Button passButton = findViewById(R.id.pass_button);

        quit.setOnClickListener(v -> finish());
        submitButton.setOnClickListener(v -> submitGuess());
        passButton.setOnClickListener(v -> advanceStep());

        renderStep();
        startTimer();
    }

    private void startTimer() {
        if (timer != null) timer.cancel();
        timer = new CountDownTimer(10000, 1000) {
            @Override
            public void onTick(long millisUntilFinished) {
                timerView.setText(getString(R.string.time_remaining, millisUntilFinished / 1000));
            }

            @Override
            public void onFinish() {
                advanceStep();
            }
        }.start();
    }

    private void renderStep() {
        stepNumber.setText(getString(R.string.step, stepIndex + 1));
        hintText.setText(HINTS[Math.min(stepIndex, HINTS.length - 1)]);
        scoreValue.setText(String.valueOf(score));
        guessInput.setText("");
    }

    private void submitGuess() {
        String guess = guessInput.getText() == null ? "" : guessInput.getText().toString().trim().toLowerCase();
        if (guess.isEmpty()) {
            Toast.makeText(this, R.string.fill_all_fields, Toast.LENGTH_SHORT).show();
            return;
        }
        if (guess.equals(solution)) {
            finishGame(true, score, 0);
        } else {
            advanceStep();
        }
    }

    private void advanceStep() {
        stepIndex++;
        score = Math.max(5, 20 - stepIndex * 2);
        if (stepIndex >= HINTS.length - 1) {
            finishGame(false, 0, 5);
            return;
        }
        renderStep();
        startTimer();
    }

    private void finishGame(boolean won, int playerScore, int opponentScore) {
        if (timer != null) timer.cancel();
        User user = userRepository.getCurrentUser();
        if (user != null) {
            resultRepository.insert(new GameResult(user.id, GameResult.GAME_KORAK_PO_KORAK, playerScore,
                    opponentScore, won, stepIndex + 1, 7, System.currentTimeMillis()));
        }
        Toast.makeText(this, won ? "Pogodio si korak po korak!" : "Kraj igre", Toast.LENGTH_LONG).show();
        finish();
    }
}

