package com.example.myapplication;

import android.os.Bundle;
import android.os.CountDownTimer;
import android.view.ViewGroup;
import android.widget.Button;
import android.widget.GridLayout;
import android.widget.ScrollView;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.example.myapplication.data.GameResultRepository;
import com.example.myapplication.data.UserRepository;
import com.example.myapplication.model.GameResult;
import com.example.myapplication.model.User;

import java.util.ArrayDeque;
import java.util.Arrays;
import java.util.Deque;

public class MojBrojActivity extends AppCompatActivity {

    private static final int TARGET = 500;
    private static final int[] ROUND_NUMBERS = {50, 50, 9, 7, 3, 2};

    private TextView timerView;
    private TextView targetView;
    private TextView expressionView;
    private TextView resultView;
    private TextView scoreView;
    private CountDownTimer timer;
    private final StringBuilder expression = new StringBuilder();
    private int score;
    private UserRepository userRepository;
    private GameResultRepository resultRepository;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_moj_broj);
        userRepository = new UserRepository(this);
        resultRepository = new GameResultRepository(this);

        ViewGroup root = (ViewGroup) findViewById(android.R.id.content).getRootView();
        ViewGroup outer = (ViewGroup) root.getChildAt(0);
        ScrollView scrollView = (ScrollView) outer.getChildAt(1);
        ViewGroup content = (ViewGroup) scrollView.getChildAt(0);

        Button quit = (Button) outer.getChildAt(0);
        timerView = (TextView) outer.getChildAt(0).getRootView().findViewById(R.id.timer);
        targetView = (TextView) content.getChildAt(0).findViewById(R.id.target_number);
        expressionView = (TextView) content.getChildAt(7);
        resultView = (TextView) content.getChildAt(9);
        scoreView = (TextView) outer.getChildAt(2).findViewById(R.id.score_value);
        Button submit = (Button) content.getChildAt(10);

        quit.setOnClickListener(v -> finish());
        bindNumberButtons((GridLayout) content.getChildAt(3));
        bindOperatorButtons((GridLayout) content.getChildAt(5));
        submit.setOnClickListener(v -> evaluateExpression());

        startRound();
    }

    private void startRound() {
        expression.setLength(0);
        score = 0;
        targetView.setText(String.valueOf(TARGET));
        expressionView.setText(R.string.expr_placeholder);
        resultView.setText(R.string.result_placeholder);
        scoreView.setText(String.valueOf(score));
        startTimer();
    }

    private void startTimer() {
        if (timer != null) timer.cancel();
        timer = new CountDownTimer(60000, 1000) {
            @Override
            public void onTick(long millisUntilFinished) {
                timerView.setText(getString(R.string.time_remaining, millisUntilFinished / 1000));
            }

            @Override
            public void onFinish() {
                finishRound(false);
            }
        }.start();
    }

    private void bindNumberButtons(GridLayout grid) {
        for (int i = 0; i < grid.getChildCount() && i < ROUND_NUMBERS.length; i++) {
            Button button = (Button) grid.getChildAt(i);
            int number = ROUND_NUMBERS[i];
            button.setText(String.valueOf(number));
            button.setOnClickListener(v -> appendToken(String.valueOf(number)));
        }
    }

    private void bindOperatorButtons(GridLayout grid) {
        String[] ops = {"(", ")", "+", "-", "*", "/"};
        for (int i = 0; i < grid.getChildCount() && i < ops.length; i++) {
            Button button = (Button) grid.getChildAt(i);
            String op = ops[i];
            button.setOnClickListener(v -> appendToken(op));
        }
    }

    private void appendToken(String token) {
        if (expression.length() > 0) {
            expression.append(' ');
        }
        expression.append(token);
        expressionView.setText(expression.toString());
    }

    private void evaluateExpression() {
        if (expression.length() == 0) {
            Toast.makeText(this, "Popuni sva polja", Toast.LENGTH_SHORT).show();
            return;
        }
        try {
            double result = evaluate(expression.toString());
            resultView.setText(String.valueOf((int) result));
            score = Math.max(0, 10 - Math.min(10, (int) Math.abs(TARGET - result) / 25));
            scoreView.setText(String.valueOf(score));
            finishRound(Math.abs(TARGET - result) < 0.001);
        } catch (Exception e) {
            Toast.makeText(this, "Neispravan izraz", Toast.LENGTH_SHORT).show();
        }
    }

    private double evaluate(String expr) {
        Deque<Double> values = new ArrayDeque<>();
        Deque<String> ops = new ArrayDeque<>();
        for (String token : expr.split(" ")) {
            if (token.isEmpty()) continue;
            if (token.matches("\\d+")) {
                values.push(Double.parseDouble(token));
                continue;
            }
            if (token.equals("(")) {
                ops.push(token);
                continue;
            }
            if (token.equals(")")) {
                while (!ops.isEmpty() && !ops.peek().equals("(")) {
                    apply(values, ops.pop());
                }
                if (!ops.isEmpty()) ops.pop();
                continue;
            }
            while (!ops.isEmpty() && precedence(ops.peek()) >= precedence(token)) {
                apply(values, ops.pop());
            }
            ops.push(token);
        }
        while (!ops.isEmpty()) {
            apply(values, ops.pop());
        }
        return values.isEmpty() ? 0 : values.pop();
    }

    private int precedence(String op) {
        if (op.equals("+") || op.equals("-")) return 1;
        if (op.equals("*") || op.equals("/")) return 2;
        return 0;
    }

    private void apply(Deque<Double> values, String op) {
        if (values.size() < 2) return;
        double right = values.pop();
        double left = values.pop();
        switch (op) {
            case "+": values.push(left + right); break;
            case "-": values.push(left - right); break;
            case "*": values.push(left * right); break;
            case "/": values.push(right == 0 ? left : left / right); break;
        }
    }

    private void finishRound(boolean won) {
        if (timer != null) timer.cancel();
        User user = userRepository.getCurrentUser();
        if (user != null) {
            resultRepository.insert(new GameResult(user.id, GameResult.GAME_MOJ_BROJ, score, 0, won, (int) Math.round(Math.abs(TARGET - score)), ROUND_NUMBERS.length, System.currentTimeMillis()));
        }
        Toast.makeText(this, "Kraj partije", Toast.LENGTH_SHORT).show();
        finish();
    }
}

